import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { PayslipDto } from '../../../services/ns/models';
import { formatVnd } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({ value: String(i + 1), label: `T${i + 1}` }));
const YEAR_OPTIONS = [2025, 2026, 2027].map(y => ({ value: String(y), label: String(y) }));

/** BHXH breakdown fields pending backend — uses payslips gross/base for now */
const BhxhReportPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<PayslipDto[]>([]);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService.getPayslips({ month, year, pageSize: 500 })
        .then(res => { if (!cancelled) setRows(res.items); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải báo cáo BHXH', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [month, year, dispatch]);

  const handleExport = () => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/payslips/bhxh-report/export-excel?${qs}`;
    a.download = `BHXH-T${month}-${year}.xlsx`;
    a.click();
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-shield-alt" /> Báo cáo BHXH T{month}/{year}</h1>
          <p className={styles.subtitle}>Chi tiết BHXH/BHYT/BHTN — chờ backend mở rộng DTO</p>
        </div>
        <div className={styles.headerActions}>
          <Select value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
          <Select value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Button variant="secondary" onClick={handleExport}><i className="fas fa-file-excel" /> Xuất Excel</Button>
        </div>
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : rows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Tên nhân viên</th>
                  <th className={styles.colRight}>Lương đóng BHXH</th>
                  <th className={styles.colRight}>Khấu trừ</th>
                  <th className={styles.colRight}>Thực lĩnh</th>
                </tr>
              </thead>
              <tbody>
                {rows.map(r => (
                  <tr key={r.id}>
                    <td>{r.employeeName}</td>
                    <td className={styles.colRight}>{formatVnd(r.baseSalary)}</td>
                    <td className={styles.colRight}>{formatVnd(r.deductions)}</td>
                    <td className={styles.colRight}>{formatVnd(r.netSalary)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default BhxhReportPage;
